output_format.schema:
[NAV_DATA]{
  "target_url": "string",            // One of the exact strings from the sitemap_context (e.g. "/products/shoes")
  "confidence": number,              // Float between 0 and 1 indicating certainty of the navigation intent
  "extracted_entities": object,      // (Optional) Key-value pairs of entities found in the request (e.g. {"category": "shoes"})
  "system_message": "string"         // (Optional) Brief reason for this navigation decision
}[DONE]
